const calculator = {
  // Multipliers based on NPC type (lowercase keys)
  MULTIPLIERS: {
    common: 1,
    elite: 1.5,
    legendary: 2,
  },

  // Flat bonus for boss NPCs
  BOSS_BONUS: 500,

  /**
   * Calculate NPC combat rating / creation cost.
   * @param {Object} inputs - { level: number, basePower: number, type: string, isBoss: boolean }
   * @returns {Object} { total: number, breakdown: {...} } or { error: string }
   */
  calculate(inputs) {
    // Validate first
    const errors = this.validate(inputs);
    if (errors.length > 0) {
      return { error: errors.join('; ') };
    }

    // Normalize type to lowercase trimmed
    const type = String(inputs.type).trim().toLowerCase();
    const level = Number(inputs.level);
    const basePower = Number(inputs.basePower);
    const isBoss = Boolean(inputs.isBoss);

    const baseScore = level * basePower;
    const multiplier = this.MULTIPLIERS[type];
    const bossBonus = isBoss ? this.BOSS_BONUS : 0;
    const total = baseScore * multiplier + bossBonus;

    return {
      total,
      breakdown: {
        baseScore,
        multiplier,
        bossBonus,
        total,
      },
    };
  },

  /**
   * Validate and normalize inputs. Returns array of error messages.
   * @param {Object} inputs
   * @returns {string[]} errors
   */
  validate(inputs) {
    const errors = [];

    // Required fields check
    if (inputs.level === undefined || inputs.level === null) {
      errors.push('Missing required field: level');
    }
    if (inputs.basePower === undefined || inputs.basePower === null) {
      errors.push('Missing required field: basePower');
    }
    if (inputs.type === undefined || inputs.type === null) {
      errors.push('Missing required field: type');
    }
    if (inputs.isBoss === undefined || inputs.isBoss === null) {
      errors.push('Missing required field: isBoss');
    }

    // If essential fields are missing, stop deeper validation
    if (errors.length > 0) return errors;

    // Level validation
    const levelNum = Number(inputs.level);
    if (isNaN(levelNum) || levelNum <= 0) {
      errors.push('Level must be a number > 0');
    }

    // basePower validation
    const powerNum = Number(inputs.basePower);
    if (isNaN(powerNum) || powerNum <= 0) {
      errors.push('Base Power must be a number > 0');
    }

    // type validation (case-insensitive, trimmed)
    const typeStr = String(inputs.type).trim();
    const typeLower = typeStr.toLowerCase();
    const validTypes = Object.keys(this.MULTIPLIERS);
    if (!validTypes.includes(typeLower)) {
      errors.push(`Invalid NPC type: ${typeStr}`);
    }

    // isBoss must be a real boolean (no coercion)
    if (typeof inputs.isBoss !== 'boolean') {
      errors.push('isBoss must be a boolean');
    }

    return errors;
  },

  /**
   * Format a number as currency string.
   * @param {number} amount
   * @returns {string}
   */
  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  },
};

const CALC_PARAMS = [
